    "dataSources": {
        "ds_pLHakJuh": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_asset_targets | where splunk_managed_lifecycle == \"PRESENT\" \n|  table AccountMoid, account_name",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "intersight_accounts_list"
        },
        "ds_FFYhGPLT": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_asset_targets | where splunk_managed_lifecycle == \"PRESENT\" \n|  search AccountMoid=\"$in_acc$\" | rename \"RegisteredDevice.Moid\" as rd_moid | table rd_moid, Name | dedup rd_moid ",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "domains_list"
        },
        "ds_1nVk8IP6": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" \n| eval objtype=\"server\" \n| where objtype=\"$obj_typ$\" | search AccountMoid=\"$in_acc$\" | rename Owners.Owners as owners | mvexpand owners | where AccountMoid != owners | search owners=\"$in_dom$\" | table SourceObjectType | dedup SourceObjectType | eval label=case(SourceObjectType=\"compute.RackUnit\", \"Compute RackUnit\", true(), \"Compute Blade\")",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "servertypes_list"
        },
        "ds_64huQuCt": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | eval objtype=\"server\" | where objtype=\"$obj_typ$\" | rename Owners.Owners as owners | mvexpand owners | search owners!=AccountMoid AND AccountMoid=\"$in_acc$\" AND owners=\"$in_dom$\" AND Model=\"$obj_mod$\"  | rename Moid as sourcemoid | table sourcemoid, Name, Model, AlarmSummary.Health | join type=left sourcemoid [| inputlookup cisco_intersight_asset_devicecontractinformations | where splunk_managed_lifecycle == \"PRESENT\" | rename Source.Moid as sourcemoid | fields ContractStatus, sourcemoid] | join type=left sourcemoid \n    [| inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" | rename AssignedServer.Moid as sourcemoid, Name as \"UCS Server Profile\" | fields sourcemoid, \"UCS Server Profile\"] | rename chassismoid as _chassismoid, sourcemoid as _sourcemoid \n|  dedup _sourcemoid",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "servers_list"
        },
        "ds_JOQ81DOk": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | eval objtype=\"server\" \n| where objtype=\"$obj_typ$\" | search AccountMoid=\"$in_acc$\" AND Model=\"$obj_mod$\" AND Moid=\"$serveridd$\" | rename Owners.Owners as owners | mvexpand owners | where owners!=AccountMoid | search owners=\"$in_dom$\" | rename Moid as sourcemoid, Parent.Moid as chassismoid | fields AlarmSummary.Health, UserLabel, Serial, Vendor, AssetTag, ManagementMode, Firmware, Lifecycle, MgmtIpAddress, Model, sourcemoid, chassismoid | join type=left sourcemoid [| inputlookup cisco_intersight_asset_devicecontractinformations | where splunk_managed_lifecycle == \"PRESENT\" | rename Source.Moid as sourcemoid | fields ContractStatus, LastDateOfSupport, ContractStatusReason, sourcemoid] | join type=left chassismoid [| inputlookup cisco_intersight_equipment_chasses | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as chassismoid, Name as chassisname | fields chassismoid, chassisname] | join type=left sourcemoid \n    [| inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" | rename AssignedServer.Moid as sourcemoid, Name as \"UCS Server Profile\", DeployStatus as \"UCS Server Profile Status\" | fields sourcemoid, \"UCS Server Profile\", \"UCS Server Profile Status\"] | rename chassismoid as _chassismoid, sourcemoid as _sourcemoid\n| transpose \n| rename \"row 1\" as row1\n| where row1!=\"\"",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "server_details"
        },
        "ds_kfom2UEH_ds_JOQ81DOk": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | eval objtype=\"server\" \n| where objtype=\"$obj_typ$\" | search AccountMoid=\"$in_acc$\" AND Model=\"$obj_mod$\" AND Moid=\"$serveridd$\" | rename Owners.Owners as owners | mvexpand owners | where owners!=AccountMoid | search owners=\"$in_dom$\" | fields OperPowerState, NumCpus, NumThreads, NumCpuCores, NumCpuCoresEnabled, CpuCapacity, AvailableMemory, Uuid, NumAdaptors\n|  transpose\n| rename \"row 1\" as row1\n| where row1!=\"\"",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "server_properties"
        },
        "ds_RGqYG7gH": {
            "type": "ds.search",
            "options": {
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\" \n| eval svrcount=\"$server_details:job.resultCount$\"\n| eval ficount=\"$fi_details:job.resultCount$\"\n| eval chcount=\"$chassis_details:job.resultCount$\"\n| where svrcount > 0 OR ficount > 0 OR chcount > 0\n| where AffectedMoId=\"$serveridd$\" OR AncestorMoId=\"$serveridd$\" | stats count by Severity",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "alarmsdistbyseverity"
        },
        "ds_8vtdk1oO": {
            "type": "ds.search",
            "options": {
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:auditrecords\" \"HttpResponsePayload.Server.Moid\"=\"*\"\n| eval svrcount=\"$server_details:job.resultCount$\"\n| eval ficount=\"$fi_details:job.resultCount$\"\n| eval chcount=\"$chassis_details:job.resultCount$\"\n| where svrcount > 0 OR ficount > 0 OR chcount > 0\n| rename HttpResponsePayload.Server.Moid as serverid, HttpResponsePayload.Owners{} as domainid | search AccountMoid=\"$in_acc$\" AND domainid=\"$in_dom$\" AND serverid=\"$serveridd$\"",
                "enableSmartSources": true,
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "Audit logs"
        },
        "ds_Gqdm9Dxz": {
